// ImportDataSidebar.js

import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ credentials }) {
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  const [jiraData, setJiraData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Validate if credentials are passed correctly
  useEffect(() => {
    if (!credentials) {
      setError('Credentials not found');
    }
  }, [credentials]);

  const fetchJiraData = async () => {
    if (!credentials || !credentials.domain) {
      setError('Invalid credentials. Domain is required.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await fetch(
        `https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${credentials.domain}&project=${project}&issueType=${issueType}`
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Jira data.');
      }

      const data = await response.json();
      setJiraData(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="import-sidebar">
      <button className="close-btn">X</button>
      <div className="sidebar-title"><strong>Fetch Jira User Stories</strong></div>

      <div className="input-fields">
        {/* Validate credentials before accessing properties */}
        <input
          type="text"
          placeholder="Domain"
          value={credentials ? credentials.domain : ''}
          disabled
        />
        <input
          type="text"
          placeholder="Project"
          value={project}
          onChange={(e) => setProject(e.target.value)}
        />
        <input
          type="text"
          placeholder="Issue Type"
          value={issueType}
          onChange={(e) => setIssueType(e.target.value)}
        />
      </div>

      <button className="fetch-btn" onClick={fetchJiraData} disabled={loading || !credentials}>
        {loading ? 'Loading...' : 'Fetch User Stories'}
      </button>

      {error && <div className="error-message">{error}</div>}

      <div className="jira-data">
        {jiraData.length > 0 && (
          <ul>
            {jiraData.map((story, index) => (
              <li key={index}>{story.title}</li>
            ))}
          </ul>
        )}
        {jiraData.length === 0 && !loading && !error && <p>No user stories found.</p>}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
